class Solution(object):
    def checkDistances(self, s, distance):
        first_occur = {}
        for i, char in enumerate(s):
            char_idx = ord(char) - ord('a')
            if char in first_occur:
                if i - first_occur[char] - 1 != distance[char_idx]:
                    return False
            else:
                first_occur[char] = i
        return True
